diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
index 6e4689863407..e4f7b40f4010 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
@@ -1330,26 +1330,107 @@ Value *InstCombinerImpl::foldAndOrOfICmpsUsingRanges(ICmpInst *ICmp1,
   // Look through add of a constant offset on V1, V2, or both operands. This
   // allows us to interpret the V + C' < C'' range idiom into a proper range.
   const APInt *Offset1 = nullptr, *Offset2 = nullptr;
+  const APInt *Mask1 = nullptr, *Mask2 = nullptr;
   if (V1 != V2) {
     Value *X;
     if (match(V1, m_Add(m_Value(X), m_APInt(Offset1))))
       V1 = X;
     if (match(V2, m_Add(m_Value(X), m_APInt(Offset2))))
       V2 = X;
+    // Handle (X & Mask) == C pattern for OR of ranges where the mask creates
+    // a contiguous range. For (X & Mask) == C, if Mask has the form -1 << k
+    // (i.e., all higher bits set), this is equivalent to X being in the range
+    // [C, C | ~Mask].
+    if (V1 != V2 && ICmpInst::isEquality(Pred1) && !Offset1 &&
+        match(V1, m_And(m_Value(X), m_APInt(Mask1)))) {
+      // Check if the mask clears low bits starting from bit 0 (mask = ~0 << k)
+      if ((-(*Mask1)).isPowerOf2()) {
+        // (X & Mask) == C creates range [C, C | ~Mask]
+        // We need to ensure this works for both eq and ne
+        V1 = X;
+      } else {
+        Mask1 = nullptr;
+      }
+    }
+    if (V1 != V2 && ICmpInst::isEquality(Pred2) && !Offset2 &&
+        match(V2, m_And(m_Value(X), m_APInt(Mask2)))) {
+      if ((-(*Mask2)).isPowerOf2()) {
+        V2 = X;
+      } else {
+        Mask2 = nullptr;
+      }
+    }
+  }
+
+  // Look through and with a negative power of 2 mask on V1 or V2. This
+  // detects idioms of the form `(x == A) || ((x & Mask) == A + 1)` where A + 1
+  // is aligned to the mask and A + 1 >= |Mask|. This pattern corresponds to a
+  // contiguous range check, which can be folded into an addition and compare.
+  // The same applies for `(x != A) && ((x & Mask) != A + 1)`.
+  auto AreContiguousRangePredicates = [](CmpPredicate Pred1, CmpPredicate Pred2,
+                                         bool IsAnd) {
+    if (IsAnd)
+      return Pred1 == ICmpInst::ICMP_NE && Pred2 == ICmpInst::ICMP_NE;
+    return Pred1 == ICmpInst::ICMP_EQ && Pred2 == ICmpInst::ICMP_EQ;
+  };
+  const APInt *ContiguousMask1 = nullptr, *ContiguousMask2 = nullptr;
+  bool MatchedAnd1 = false, MatchedAnd2 = false;
+  if (V1 != V2 && AreContiguousRangePredicates(Pred1, Pred2, IsAnd)) {
+    Value *X;
+    if (match(V1, m_OneUse(m_And(m_Value(X), m_NegatedPower2(ContiguousMask1)))) &&
+        C1->getBitWidth() == C2->getBitWidth() && *C1 == *C2 + 1 &&
+        C1->uge(ContiguousMask1->abs()) && C1->isPowerOf2()) {
+      MatchedAnd1 = true;
+      V1 = X;
+    }
+    if (match(V2, m_OneUse(m_And(m_Value(X), m_NegatedPower2(ContiguousMask2)))) &&
+        C1->getBitWidth() == C2->getBitWidth() && *C2 == *C1 + 1 &&
+        C2->uge(ContiguousMask2->abs()) && C2->isPowerOf2()) {
+      MatchedAnd2 = true;
+      V2 = X;
+    }
   }

   if (V1 != V2)
     return nullptr;

-  ConstantRange CR1 = ConstantRange::makeExactICmpRegion(
-      IsAnd ? ICmpInst::getInverseCmpPredicate(Pred1) : Pred1, *C1);
+  ConstantRange CR1 =
+      MatchedAnd1
+          ? ConstantRange(*C1, *C1 - *ContiguousMask1)
+          : ConstantRange::makeExactICmpRegion(
+                IsAnd ? ICmpInst::getInverseCmpPredicate(Pred1) : Pred1, *C1);
   if (Offset1)
     CR1 = CR1.subtract(*Offset1);
-
-  ConstantRange CR2 = ConstantRange::makeExactICmpRegion(
-      IsAnd ? ICmpInst::getInverseCmpPredicate(Pred2) : Pred2, *C2);
+  if (Mask1 && Pred1 == ICmpInst::ICMP_EQ) {
+    // (X & Mask) == C is equivalent to X in [C, C | ~Mask]
+    APInt Lower = *C1;
+    APInt Upper = (*C1 | ~*Mask1) + 1;
+    CR1 = ConstantRange(Lower, Upper);
+  } else if (Mask1 && Pred1 == ICmpInst::ICMP_NE) {
+    // (X & Mask) != C is the inverse
+    APInt Lower = *C1;
+    APInt Upper = (*C1 | ~*Mask1) + 1;
+    CR1 = ConstantRange(Lower, Upper).inverse();
+  }
+
+  ConstantRange CR2 =
+      MatchedAnd2
+          ? ConstantRange(*C2, *C2 - *ContiguousMask2)
+          : ConstantRange::makeExactICmpRegion(
+                IsAnd ? ICmpInst::getInverseCmpPredicate(Pred2) : Pred2, *C2);
   if (Offset2)
     CR2 = CR2.subtract(*Offset2);
+  if (Mask2 && Pred2 == ICmpInst::ICMP_EQ) {
+    // (X & Mask) == C is equivalent to X in [C, C | ~Mask]
+    APInt Lower = *C2;
+    APInt Upper = (*C2 | ~*Mask2) + 1;
+    CR2 = ConstantRange(Lower, Upper);
+  } else if (Mask2 && Pred2 == ICmpInst::ICMP_NE) {
+    // (X & Mask) != C is the inverse
+    APInt Lower = *C2;
+    APInt Upper = (*C2 | ~*Mask2) + 1;
+    CR2 = ConstantRange(Lower, Upper).inverse();
+  }

   Type *Ty = V1->getType();
   Value *NewV = V1;

